    menu_name, parent_id, menu_type, path, component, permission, icon,
    order_num, is_frame, is_cache, visible, status,
    create_by, create_time, update_by, update_time, deleted, remark
) VALUES (
    #{menuName}, #{parentId}, #{menuType}, #{path}, #{component}, #{permission}, #{icon},
    #{orderNum}, #{isFrame}, #{isCache}, #{visible}, #{status},
